   Archive,
   ArrowLeft,
   Building2,
   Clock,
   Edit,
   MapPin,
 } from "lucide-react";
 import { useState } from "react";

 import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
 import { Badge } from "@/components/ui/badge";
 import { Button } from "@/components/ui/button";
 import {
   Card,
